import requests

def trace_redirects(url):
    history = [url]

    while True:
        url = re.sub(r'https?://example.com', '', url)
        if 'example.com' in url:
            resp = requests.get(url)

            if resp.is_redirect:
                url = resp.headers['location']

                if url in history:
                    break

                history.append(url)
            else:
                break

    print(history)

